def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = np.inf
            continue
        score = 0
        decay = 1.0
        step = 0
        while step < 5:
            if ratio < 0.05:
                score += (np.exp(-ratio) + np.log1p(step + 1)) * decay
            elif 0.05 <= ratio <= 0.5:
                score += (np.sqrt(ratio*10) + (step + 1)**0.5) * decay
            else:
                if step % 2 == 0:
                    score += (ratio * 5 - step) * decay
                else:
                    score += (np.sin(ratio * np.pi) * (step+1)) * decay
            decay *= 0.7
            ratio *= 0.85
            step += 1
            if decay < 0.01:
                break
        if capacity < item * 0.5:
            score += 5
        if np.isclose(score, 0):
            priorities[i] = 1000
        elif score < 1:
            priorities[i] = score * 15
        else:
            priorities[i] = max(score, 10)
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    min_priority = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority * 50
    return priorities
